        <input type="text" name="jenis_kegiatan" id="jenis_kegiatan" class="form-control" placeholder="Contoh: UP 1 UDP 1/8" required>
    </div>
    <div class="col-md-6">
        <label class="form-label fw-bold">Lokasi</label>
        <input type="text" name="lokasi" id="lokasi" class="form-control" placeholder="Contoh: Banteng Mati" required>
    </div>
</div>

<div class="row mb-3">
