    </div>
    <div class="col-md-6">
        <label class="form-label fw-bold">End Koordinat</label>
        <input type="text" name="end_koordinat" id="end_koordinat" class="form-control" placeholder="0.000, 0.000" required>
    </div>
</div>

<div class="row mb-3">
