    </div>
    <div class="col-md-4">
        <label class="form-label fw-bold">Banyak Core</label>
        <input type="text" name="banyak_core" id="banyak_core" class="form-control" placeholder="Contoh: 12 Core" required>
    </div>
    <div class="col-md-4">
        <label class="form-label fw-bold">Jenis Kabel</label>
        <input type="text" name="jenis_kabel" id="jenis_kabel" class="form-control" placeholder="Contoh: ADSS" required>
    </div>
</div>

